// test_reset.cpp - Reset operations tests
// Tests for git_reset() with Soft, Mixed, and Hard modes
#include "test_harness.h"

// Path to fixture repository (source for copies)
static const wchar_t* RESET_TEST_FIXTURE_PATH = L"test\\fixtures\\test_repo";

// Path to current temp test repo (empty if none active)
static wchar_t g_reset_test_repo[512] = {};

// Forward declarations from test_write.cpp
extern bool delete_directory_recursive(const wchar_t* path);
extern bool copy_directory_recursive(const wchar_t* src, const wchar_t* dst);

// Create fresh temp copy of fixture repo for reset tests
static bool create_reset_test_repo() {
    // First, cleanup any stale temp repo from previous run
    if (g_reset_test_repo[0] != L'\0') {
        delete_directory_recursive(g_reset_test_repo);
        g_reset_test_repo[0] = L'\0';
    }

    // Get TEMP directory
    wchar_t temp_base[512];
    DWORD len = GetTempPathW(512, temp_base);
    if (len == 0 || len >= 512) {
        return false;
    }

    // Create unique temp directory
    wchar_t temp_path[512];
    wcscpy_s(temp_path, temp_base);
    wcscat_s(temp_path, L"GitSmarter_reset_test_");

    // Append timestamp for uniqueness
    LARGE_INTEGER counter;
    QueryPerformanceCounter(&counter);
    wchar_t suffix[32];
    swprintf_s(suffix, L"%llx", counter.QuadPart);
    wcscat_s(temp_path, suffix);

    // Copy fixture repo to temp location
    if (!copy_directory_recursive(RESET_TEST_FIXTURE_PATH, temp_path)) {
        delete_directory_recursive(temp_path);
        return false;
    }

    wcscpy_s(g_reset_test_repo, temp_path);
    return true;
}

// Delete temp repo and clear g_reset_test_repo
static void cleanup_reset_test_repo() {
    if (g_reset_test_repo[0] != L'\0') {
        delete_directory_recursive(g_reset_test_repo);
        g_reset_test_repo[0] = L'\0';
    }
}

// Helper: Get SHA of HEAD~1 (parent of HEAD)
static bool get_parent_sha(GitRepository* repo, char* out_sha) {
    GitCommit head = {};
    if (!git_read_commit(repo, repo->head_sha, &head)) {
        return false;
    }
    if (head.parent_sha[0] == '\0') {
        return false; // No parent
    }
    strcpy_s(out_sha, Git::SHA1_HEX_SIZE + 1, head.parent_sha);
    return true;
}

// ============================================================================
// Reset Tests
// ============================================================================

TEST(reset_soft_moves_head) {
    if (!create_reset_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_reset_test_repo)) {
        cleanup_reset_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get parent SHA
    char parent_sha[41] = {};
    if (!get_parent_sha(&repo, parent_sha)) {
        git_repo_close(&repo);
        cleanup_reset_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    char original_head[41];
    strcpy_s(original_head, repo.head_sha);

    // Perform soft reset to parent
    char error[256] = {};
    bool result = git_reset(&repo, parent_sha, ResetMode::Soft, error, sizeof(error));
    TEST_ASSERT_TRUE(result);

    // Re-read HEAD
    TEST_ASSERT_TRUE(git_read_head(&repo));

    // HEAD should now point to parent
    TEST_ASSERT_STREQ(repo.head_sha, parent_sha);

    git_repo_close(&repo);
    cleanup_reset_test_repo();
}

