TEST(reset_hard_changes_all) {
    if (!create_reset_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_reset_test_repo)) {
        cleanup_reset_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get parent SHA
    char parent_sha[41] = {};
    if (!get_parent_sha(&repo, parent_sha)) {
        git_repo_close(&repo);
        cleanup_reset_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    // Perform hard reset to parent
    char error[256] = {};
    bool result = git_reset(&repo, parent_sha, ResetMode::Hard, error, sizeof(error));
    TEST_ASSERT_TRUE(result);

    // Re-read HEAD
    TEST_ASSERT_TRUE(git_read_head(&repo));

    // HEAD should now point to parent
    TEST_ASSERT_STREQ(repo.head_sha, parent_sha);

    // Working tree should be clean (no modified tracked files)
    // Note: Untracked files are preserved by git reset --hard (correct behavior)
    GitStatus status = {};
    TEST_ASSERT_TRUE(git_status_compute(&repo, &status));
    TEST_ASSERT_EQ(status.staged_count, 0);

    // Count only modified/deleted tracked files (not untracked)
    size_t modified_count = 0;
    for (size_t i = 0; i < status.unstaged_count; i++) {
        if (status.unstaged[i].worktree_status != GitFileStatus::Untracked) {
            modified_count++;
        }
    }
    TEST_ASSERT_EQ(modified_count, 0);
    git_status_free(&status);

    git_repo_close(&repo);
    cleanup_reset_test_repo();
}

