TEST(reset_detached_head) {
    if (!create_reset_test_repo()) {
        TEST_SKIP("Could not create temp test repo");
    }

    GitRepository repo = {};
    if (!git_repo_open(&repo, g_reset_test_repo)) {
        cleanup_reset_test_repo();
        TEST_SKIP("Could not open temp repo");
    }

    // Get parent SHA
    char parent_sha[41] = {};
    if (!get_parent_sha(&repo, parent_sha)) {
        git_repo_close(&repo);
        cleanup_reset_test_repo();
        TEST_SKIP("HEAD has no parent");
    }

    // Put repo in detached HEAD state by writing SHA directly to HEAD
    wchar_t head_path[512];
    wcscpy_s(head_path, g_reset_test_repo);
    wcscat_s(head_path, L"\\.git\\HEAD");

    char head_content[64];
    snprintf(head_content, sizeof(head_content), "%s\n", repo.head_sha);
    write_file_atomic(head_path, head_content, strlen(head_content));

    // Re-read HEAD (should be detached now)
    TEST_ASSERT_TRUE(git_read_head(&repo));
    TEST_ASSERT_TRUE(repo.head_detached);

    // Reset should still work in detached state
    char error[256] = {};
    bool result = git_reset(&repo, parent_sha, ResetMode::Soft, error, sizeof(error));
    TEST_ASSERT_TRUE(result);

    TEST_ASSERT_TRUE(git_read_head(&repo));
    TEST_ASSERT_STREQ(repo.head_sha, parent_sha);
    TEST_ASSERT_TRUE(repo.head_detached);

    git_repo_close(&repo);
    cleanup_reset_test_repo();
}

